module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

    parameter WIDTH_A = 8;
    parameter WIDTH_B = 8;
    parameter WIDTH_OUT = 16;

    reg [1:0] mul_en_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            mul_en_out_reg <= 0;
            mul_en_out <= 0;
        end else begin
            mul_en_out_reg <= {mul_en_out_reg[0], mul_en_in};
            mul_en_out <= mul_en_out_reg[1];
        end
    end

    reg [WIDTH_A-1:0] mul_a_reg;
    reg [WIDTH_B-1:0] mul_b_reg;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            mul_a_reg <= 0;
            mul_b_reg <= 0;
        end else begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end

    wire [WIDTH_A+WIDTH_B-1:0] temp[0:7];

    assign temp[0] = {9'd0, mul_a_reg[0] ? mul_b_reg : 8'd0};
    assign temp[1] = {8'd0, mul_a_reg[1] ? mul_b_reg : 8'd0, 1'd0};
    assign temp[2] = {7'd0, mul_a_reg[2] ? mul_b_reg : 8'd0, 2'd0};
    assign temp[3] = {6'd0, mul_a_reg[3] ? mul_b_reg : 8'd0, 3'd0};
    assign temp[4] = {5'd0, mul_a_reg[4] ? mul_b_reg : 8'd0, 4'd0};
    assign temp[5] = {4'd0, mul_a_reg[5] ? mul_b_reg : 8'd0, 5'd0};
    assign temp[6] = {3'd0, mul_a_reg[6] ? mul_b_reg : 8'd0, 6'd0};
    assign temp[7] = {2'd0, mul_a_reg[7] ? mul_b_reg : 8'd0, 7'd0};

    reg [WIDTH_A+WIDTH_B-1:0] sum[0:6];

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            sum[0] <= 0;
            sum[1] <= 0;
            sum[2] <= 0;
            sum[3] <= 0;
            sum[4] <= 0;
            sum[5] <= 0;
            sum[6] <= 0;
        end else begin
            sum[0] <= temp[0];
            sum[1] <= temp[1] + temp[2];
            sum[2] <= temp[3] + temp[4];
            sum[3] <= temp[5] + temp[6];
            sum[4] <= temp[7];
        end
    end

    reg [WIDTH_OUT-1:0] mul_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            mul_out_reg <= 0;
        end else begin
            mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3] + sum[4];
        end
    end

    assign mul_out = mul_en_out_reg[1] ? mul_out_reg : 0;
endmodule
